  ('pukao-7c4986e7-moex-00045', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '假設某一市場內有甲、乙兩家廠商，他們一起商議訂價規則。假設他們都遵守的話，利潤各為1,000萬； 都不遵守的話利潤均為0；若一方遵守另一方打破規則，則遵守的廠商損失500萬，打破規則的廠商獲得 1,500萬。他們的償付矩陣（單位：萬）如下，下列敘述何者正確？', '["Nash均衡為（甲，乙）＝（遵守，遵守）", "Nash均衡為（甲，乙）＝（遵守，不遵守）", "Nash均衡為（甲，乙）＝（不遵守，遵守）", "Nash均衡為（甲，乙）＝（不遵守，不遵守）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "7f60f8d3aafd", "answer_pdf_sha1": "79d6a424ea53", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
